const e=JSON.parse('{"key":"v-3fd04daa","path":"/posts/notes/articles/%E7%AC%94%E8%AE%B0rl_2.html","title":"RL 与人格 (2026)","lang":"zh-CN","frontmatter":{"title":"RL 与人格 (2026)","date":"2026-06-20T00:00:00.000Z","author":"Kevin 吴嘉文","category":["知识笔记"],"tag":["LLM","Agent","Scaling laws"],"description":"RL 猜想 漫无目的的思考相当于预训练模型推理 如果把人类暂时比作一个 LLM，那么成长过程中的语言输入、视觉经验、社会互动和现实反馈，就类似于模型的预训练数据。人在成长中不断听到、看到、经历各种事件，类似 LLM 预训练。这一过程可以近似理解为一种广义的 distribution matching：人脑通过经验建立对世界的预测模型。 在这个类比中，LLM 的上下文长度可以对应为人类在时间中的连续意识流。模型在上下文窗口中不断预测下一个 token，而人在现实时间中不断生成念头、判断、语言和行动。当一个人没有明确目的时，脑中浮现的内容就像是在当前状态下进行采样，就好比预训练 LLM 直接用于推理。","head":[["meta",{"property":"og:url","content":"http://antarina.tech/posts/notes/articles/%E7%AC%94%E8%AE%B0rl_2.html"}],["meta",{"property":"og:site_name","content":"记忆笔书"}],["meta",{"property":"og:title","content":"RL 与人格 (2026)"}],["meta",{"property":"og:description","content":"RL 猜想 漫无目的的思考相当于预训练模型推理 如果把人类暂时比作一个 LLM，那么成长过程中的语言输入、视觉经验、社会互动和现实反馈，就类似于模型的预训练数据。人在成长中不断听到、看到、经历各种事件，类似 LLM 预训练。这一过程可以近似理解为一种广义的 distribution matching：人脑通过经验建立对世界的预测模型。 在这个类比中，LLM 的上下文长度可以对应为人类在时间中的连续意识流。模型在上下文窗口中不断预测下一个 token，而人在现实时间中不断生成念头、判断、语言和行动。当一个人没有明确目的时，脑中浮现的内容就像是在当前状态下进行采样，就好比预训练 LLM 直接用于推理。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2026-06-22T06:19:36.000Z"}],["meta",{"property":"article:author","content":"Kevin 吴嘉文"}],["meta",{"property":"article:tag","content":"LLM"}],["meta",{"property":"article:tag","content":"Agent"}],["meta",{"property":"article:tag","content":"Scaling laws"}],["meta",{"property":"article:published_time","content":"2026-06-20T00:00:00.000Z"}],["meta",{"property":"article:modified_time","content":"2026-06-22T06:19:36.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"RL 与人格 (2026)\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2026-06-20T00:00:00.000Z\\",\\"dateModified\\":\\"2026-06-22T06:19:36.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Kevin 吴嘉文\\"}]}"]]},"headers":[{"level":2,"title":"RL 猜想","slug":"rl-猜想","link":"#rl-猜想","children":[]},{"level":2,"title":"Emergent Misalignment: Narrow finetuning can produce broadly misaligned LLMs","slug":"emergent-misalignment-narrow-finetuning-can-produce-broadly-misaligned-llms","link":"#emergent-misalignment-narrow-finetuning-can-produce-broadly-misaligned-llms","children":[{"level":3,"title":"Results 结果译读","slug":"results-结果译读","link":"#results-结果译读","children":[]},{"level":3,"title":"数据多样性消融译读","slug":"数据多样性消融译读","link":"#数据多样性消融译读","children":[]}]},{"level":2,"title":"Reinforcement Learning Towards Broadly and  Persistently Beneficial Models","slug":"reinforcement-learning-towards-broadly-and-persistently-beneficial-models","link":"#reinforcement-learning-towards-broadly-and-persistently-beneficial-models","children":[]},{"level":2,"title":"术语预备","slug":"术语预备","link":"#术语预备","children":[]}],"git":{"createdTime":1782109176000,"updatedTime":1782109176000,"contributors":[{"name":"kevin","email":"kevin@PC-20230504CBNV.localdomain","commits":1}]},"readingTime":{"minutes":20.79,"words":6238},"filePathRelative":"posts/notes/articles/笔记rl_2.md","localizedDate":"2026年6月20日","excerpt":"<h2> RL 猜想</h2>\\n<ul>\\n<li>漫无目的的思考相当于预训练模型推理</li>\\n</ul>\\n<p>如果把人类暂时比作一个 LLM，那么成长过程中的语言输入、视觉经验、社会互动和现实反馈，就类似于模型的预训练数据。人在成长中不断听到、看到、经历各种事件，类似 LLM 预训练。这一过程可以近似理解为一种广义的 distribution matching：人脑通过经验建立对世界的预测模型。</p>\\n<p>在这个类比中，LLM 的上下文长度可以对应为人类在时间中的连续意识流。模型在上下文窗口中不断预测下一个 token，而人在现实时间中不断生成念头、判断、语言和行动。当一个人没有明确目的时，脑中浮现的内容就像是在当前状态下进行采样，就好比预训练 LLM 直接用于推理。</p>","autoDesc":true}');export{e as data};
